const LUNAR_BAR_WHITE_SOURCE_COLOR_MODES = Object.freeze(["white","silver","gray","lunar"]);

function normalizeLunarBarColorMode(value) {
  return typeof value === "string" ? value.trim().toLowerCase() : "";
}

function shouldUseWhiteLunarBarSource(colorMode) {
  return LUNAR_BAR_WHITE_SOURCE_COLOR_MODES.includes(normalizeLunarBarColorMode(colorMode));
}

function getLunarBarSVGSourceForColorMode(colorMode) {
  return shouldUseWhiteLunarBarSource(colorMode)
    ? LUNAR_BAR_SVG_SOURCE_WHITE
    : LUNAR_BAR_SVG_SOURCE_BLACK;
}

const LUNAR_BAR_SVG_SOURCE = LUNAR_BAR_SVG_SOURCE_BLACK;

